import '../styles/Menu.css'
import absence from '../assets/absence.png'
import employes from '../assets/employes.png'
import presence from '../assets/presence.png'
import graphique from '../assets/graphique.png'
import { Link } from 'react-router'
import supabase from './supabaseClient'
import React, {useState, useEffect} from 'react'

function Menu(){

    const [pointage, setPointage]= useState([])
    const [loading, setLoading]= useState(true)
    const [userMap, setUserMap]= useState({})
    const [userMap1, setUserMap1]= useState({})
    useEffect(() => {
    async function fetchData() {
      // 1. Charger les 3 lignes de la table Pointage
      const { data: pointageData, error: pointageError } = await supabase
        .from('USER_OF_RUN')
        .select('USERID, STARTDATE, ENDDATE')
        .limit(3)
        .order('startdate', { ascending: false })

      if (pointageError) {
        console.error('Erreur Pointage:', pointageError.message);
        return;
      }

      // 2. Extraire tous les userids uniques
      const userIds = [...new Set(pointageData.map(p => p.USERID))];

      // 3. Récupérer les infos des utilisateurs concernés
      const { data: userinfoData, error: userinfoError } = await supabase
        .from('USERINFO')
        .select('USERINFO, Name', 'TITLE')
        .in('USERID', userIds);

      if (userinfoError) {
        console.error('Erreur Userinfo:', userinfoError.message);
        return;
      }

      // 4. Créer une map userid → Nom
      const map = {};
      for (const user of userinfoData) {
        map[user.USERID] = user.Name;
      }

      setUserMap(map);
      setPointage(pointageData);
      setLoading(false);
    }

    fetchData();
  }, []);
    

    if(loading) return <p>Chargement de données...</p>

    return(
        <div>
            <p className='salutation'>Bienvenu dans TempoRH, votre application de gestions d'heures</p>
            <div className='Menu'>
                
                <div  className='bule'>
                    <div className='bule1'>
                        <img src={employes} alt='logo-employes'/>
                        <p>Employés</p>
                    </div>
                    <p className='nombre'>1080</p>
                </div>
                <div  className='bule'>
                    <div className='bule1'>
                        <img src={presence} alt='logo-presence'/>
                        <p>Présences</p>
                    </div>
                    <p className='nombre'>105 H</p>
                </div>
                <div  className='bule'>
                    <div className='bule1'>
                        <img src={absence} alt='logo-absence'/>
                        <p>Absences</p>
                    </div>
                    <p className='nombre'>50 H</p>
                </div>
                <div  className='bule'>
                    <div className='bule1'>
                        <img src={graphique} alt='logo-graphique'/>
                        <p>statistiques</p>
                    </div>
                </div>

            </div>
            <p className='auday'>Aujourd'hui, Dans Les Laboratoires Biopharma </p>
            <div className='tableau'>
                <table className='table'>
                    <thead className='t1'>
                        <tr className='champ-name'>
                            <th>ID</th>
                            <th>Nom</th>
                            <th>Titre</th>
                            <th>Heure d'arrivée</th>
                            <th>Heure de départ</th>
                        </tr>
                    </thead>
                    <tbody className='data-table'>
                    {pointage.map((p, index) => (
                        <tr key={index}>
                        <td>{p.USERID}</td>

                        <td>{p.STARTDATE}</td>
                        <td>{p.ENDDATE}</td>
                        </tr>
                    ))}
                    </tbody>
                </table>
            </div>
            <Link to="/Pointage" className='plus'>Plus</Link>

        </div>
    )
}

export default Menu
